mapper.select:
SELECT site_code AS siteCode, ANY_VALUE(task_id) AS taskId, task_type AS taskType, sub_task_type AS subTaskType, SUM( CASE WHEN receive_status = 1 THEN 1 ELSE 0 END ) AS receiveCount, COUNT(DISTINCT user_id) AS allCount, SUM( task_amount ) AS sendAmount, SUM( CASE WHEN receive_status = 1 THEN task_amount ELSE 0 END ) AS receiveAmount, currency_code as currencyCode, DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(a.created_time/1000), @@session.time_zone,#{dataReportReqVO.timeZoneDb}),'%Y-%m-%d') as staticDate, FROM site_task_order_record where 1=1
AND created_time >= #{startTime}
AND created_time <= #{endTime}
AND site_code = #{siteCode}
GROUP BY site_code, task_type, sub_task_type, currency_code, staticDate

SELECT site_code AS siteCode, ANY_VALUE(task_id) AS taskId, task_type AS taskType, sub_task_type AS subTaskType, COUNT(DISTINCT CASE WHEN receive_status = 1 THEN user_id ELSE NULL END) AS receiveCount, COUNT(DISTINCT user_id) AS allCount, SUM( task_amount ) AS sendAmount, SUM( CASE WHEN receive_status = 1 THEN task_amount ELSE 0 END ) AS receiveAmount, currency_code as currencyCode, DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(a.created_time/1000), @@session.time_zone,#{dataReportReqVO.timeZoneDb}),'%Y-%m-%d') as staticDate, FROM site_task_order_record where 1=1
AND receive_time >= #{startTime}
AND receive_time <= #{endTime}
AND site_code = #{siteCode}
GROUP BY site_code, task_type, sub_task_type, currency_code, staticDate

SELECT order_no AS orderNo FROM site_task_order_record where 1=1
AND site_code = #{siteCode}
AND receive_status = 0

select abc.siteCode AS siteCode, abc.taskId AS taskId, abc.taskType AS taskType, abc.subTaskType AS subTaskType, abc.staticDate as staticDate, abc.currencyCode as currencyCode, sum(abc.allCount) as allCount, SUM( abc.sendAmount ) AS sendAmount, sum(abc.receiveCount) AS receiveCount, sum(abc.receiveAmount) AS receiveAmount from ( SELECT a.site_code AS siteCode, a.task_id AS taskId, a.task_type AS taskType, a.sub_task_type AS subTaskType, COUNT(DISTINCT a.user_id) AS allCount, SUM( a.task_amount ) AS sendAmount, 0 AS receiveCount, 0 AS receiveAmount, a.currency_code as currencyCode, DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME( a.created_time/1000), @@session.time_zone,#{vo.timezoneDb}),'%Y-%m-%d') as staticDate FROM site_task_order_record a left join user_info b on a.user_id = b.user_id where 1=1 and b.account_type = '2'
AND a.created_time >= #{vo.startTime}
AND a.created_time <= #{vo.endTme}
AND a.site_code = #{vo.siteCode}
AND a.task_id = #{vo.taskId}
AND a.task_type = #{vo.taskType}
AND a.task_id IN
#{item}
GROUP BY a.site_code, a.task_type, a.sub_task_type, a.currency_code, staticDate, a.task_id
union all
SELECT a.site_code AS siteCode, a.task_id AS taskId, a.task_type AS taskType, a.sub_task_type AS subTaskType, 0 AS allCount, 0 AS sendAmount, COUNT(DISTINCT CASE WHEN a.receive_status = 1 THEN a.user_id ELSE NULL END) AS receiveCount, SUM( CASE WHEN a.receive_status = 1 THEN a.task_amount ELSE 0 END ) AS receiveAmount, a.currency_code as currencyCode, DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME( a.receive_time/1000), @@session.time_zone,#{vo.timezoneDb}),'%Y-%m-%d') as staticDate FROM site_task_order_record a left join user_info b on a.user_id = b.user_id where 1=1 and b.account_type = '2'
AND a.receive_time >= #{vo.startTime}
AND a.receive_time <= #{vo.endTme}
AND a.site_code = #{vo.siteCode}
AND a.task_id = #{vo.taskId}
AND a.task_type = #{vo.taskType}
AND a.task_id IN
#{item}
GROUP BY a.site_code, a.task_type, a.sub_task_type, a.currency_code, staticDate, a.task_id ) abc group by abc.siteCode, abc.taskType, abc.subTaskType, abc.currencyCode, abc.staticDate, abc.taskId order by staticDate desc

